   238→        });
   239→      }
   240→
   241→      // Load dashboard data
   242→      loadRecruiterDashboard();
   243→    });
   244→
   245→    async function loadRecruiterDashboard() {
   246→      try {
   247→        const data = await apiCall('/recruiter/dashboard');
   248→        if (!data) return;
   249→
   250→        // Update TrustScore
   251→        if (data.trust_score) {
   252→          document.getElementById('trustscore-value').textContent = data.trust_score.total_score;
   253→          document.getElementById('trustscore-tier').textContent = data.trust_score.tier_label;
   254→          document.getElementById('trustscore-tier').style.background = data.trust_score.tier_color;
   255→        }
   256→
   257→        // Update stats
   258→        document.getElementById('active-jobs').textContent = data.job_stats?.active_jobs || 0;
   259→        document.getElementById('total-applications').textContent = data.application_stats?.total_applications || 0;
   260→        document.getElementById('new-applications').textContent = data.application_stats?.new_applications || 0;
   261→
   262→        const interviewed = parseInt(data.application_stats?.interviewed) || 0;
   263→        const offered = parseInt(data.application_stats?.offered) || 0;
   264→        const ratio = interviewed > 0 ? ((offered / interviewed) * 100).toFixed(0) + '%' : '-';
   265→        document.getElementById('offer-ratio').textContent = ratio;
   266→
   267→        // Render upcoming interviews
   268→        renderUpcomingInterviews(data.upcoming_interviews || []);
   269→
   270→        // Render recent applications
   271→        renderRecentApplications(data.recent_applications || []);
   272→
