   253→    async function loadCompanyProfile() {
   254→      try {
   255→        const data = await apiCall('/company/profile');
   256→        if (!data) return;
   257→
   258→        companyData = data.company;
   259→        populateForm(companyData);
   260→        updateCompleteness(companyData);
   261→        updateVerificationStatus(companyData);
   262→      } catch (err) {
   263→        console.error('Failed to load profile:', err);
   264→      }
   265→    }
   266→
   267→    function populateForm(company) {
   268→      const form = document.getElementById('profile-form');
   269→      form.name.value = company.name || '';
   270→      form.description.value = company.description || '';
   271→      form.industry.value = company.industry || '';
   272→      form.company_size.value = company.company_size || '';
   273→      form.headquarters.value = company.headquarters || '';
   274→      form.founded_year.value = company.founded_year || '';
   275→      form.website.value = company.website || '';
   276→      form.linkedin_url.value = company.linkedin_url || '';
   277→      form.logo_url.value = company.logo_url || '';
   278→
   279→      // Update logo preview
   280→      if (company.logo_url) {
   281→        document.getElementById('logo-preview').innerHTML =
   282→          `<img src="${company.logo_url}" alt="Company logo" onerror="this.parentElement.innerHTML='<div class=\\'logo-placeholder\\'>Invalid URL</div>'">`;
   283→      }
   284→    }
   285→
   286→    function updateCompleteness(company) {
   287→      const fields = [
   288→        company.name,
   289→        company.description,
   290→        company.industry,
   291→        company.company_size,
   292→        company.headquarters,
   293→        company.website,
   294→        company.logo_url,
   295→        company.linkedin_url
   296→      ];
   297→
   298→      const completed = fields.filter(f => f && f.length > 0).length;
   299→      const percentage = Math.round((completed / fields.length) * 100);
   300→
   301→      document.getElementById('completeness-fill').style.width = percentage + '%';
   302→      document.getElementById('completeness-percent').textContent = percentage + '%';
   303→
   304→      if (percentage === 100) {
   305→        document.getElementById('completeness-card').classList.add('complete');
   306→      }
   307→    }
   308→
   309→    function updateVerificationStatus(company) {
   310→      const icon = document.getElementById('verification-icon');
   311→      const title = document.getElementById('verification-title');
   312→      const desc = document.getElementById('verification-desc');
   313→      const btn = document.getElementById('verify-btn');
   314→      const card = document.getElementById('verification-card');
   315→
   316→      if (company.is_verified) {
   317→        icon.textContent = '✅';
   318→        title.textContent = 'Verified Company';
   319→        desc.textContent = 'Your company has been verified. Candidates see a verified badge on your jobs.';
   320→        card.classList.add('verified');
   321→      } else if (company.email_domain) {
   322→        icon.textContent = '🔄';
   323→        title.textContent = 'Pending Verification';
   324→        desc.textContent = 'Your work email domain has been registered. Add LinkedIn to complete verification.';
   325→        btn.style.display = company.linkedin_url ? 'none' : 'block';
   326→      } else {
   327→        icon.textContent = '⚠️';
   328→        title.textContent = 'Not Verified';
   329→        desc.textContent = 'Use a company email address to verify your company automatically.';
   330→        btn.style.display = 'block';
   331→      }
   332→    }
   333→
   334→    document.getElementById('profile-form').addEventListener('submit', async (e) => {
   335→      e.preventDefault();
   336→      const form = e.target;
   337→      const submitBtn = form.querySelector('button[type="submit"]');
   338→      const message = document.getElementById('form-message');
   339→
   340→      submitBtn.disabled = true;
   341→      submitBtn.textContent = 'Saving...';
   342→
   343→      try {
   344→        const response = await apiCall('/company/profile', {
   345→          method: 'PUT',
   346→          body: JSON.stringify({
   347→            name: form.name.value,
   348→            description: form.description.value,
   349→            industry: form.industry.value,
   350→            company_size: form.company_size.value,
   351→            headquarters: form.headquarters.value,
   352→            founded_year: form.founded_year.value ? parseInt(form.founded_year.value) : null,
   353→            website: form.website.value,
   354→            linkedin_url: form.linkedin_url.value,
   355→            logo_url: form.logo_url.value
   356→          })
   357→        });
   358→
   359→        if (response.success) {
   360→          message.textContent = response.message || 'Profile updated successfully!';
   361→          message.className = 'form-message success';
   362→          message.style.display = 'block';
   363→
   364→          // Update completeness
   365→          if (response.company) {
   366→            updateCompleteness(response.company);
   367→          }
   368→
   369→          setTimeout(() => {
   370→            message.style.display = 'none';
   371→          }, 3000);
   372→        } else {
   373→          throw new Error(response.error || 'Failed to update profile');
   374→        }
   375→      } catch (err) {
   376→        message.textContent = err.message;
   377→        message.className = 'form-message error';
   378→        message.style.display = 'block';
   379→      } finally {
   380→        submitBtn.disabled = false;
   381→        submitBtn.textContent = 'Save Changes';
   382→      }
   383→    });
