     1→// Company Management Routes
     2→const express = require('express');
     3→const bcrypt = require('bcryptjs');
     4→const pool = require('../lib/db');
     5→const { generateToken, authMiddleware, optionalAuth } = require('../lib/auth');
     6→const trustscoreService = require('../services/trustscore');
